var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`문주님. 몰래 보물을 훔쳐가려던 녀석을 잡아왔습니다.`,JPN:`門主。こっそり宝物を盗もうとしたやつを捕まえてきました。`,ENG:`Sir, I caught the rat that was attempting to steal our treasure.`,TWN:`掌門人，抓到偷寶物的人了。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_CHILD`,text:{KOREA:`윽…!`,JPN:`うっ……！`,ENG:`Ngh...!`,TWN:`呃…！`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`흑동의 경비를 뚫고 창고까지 들어가다니. 어린 것이 제법이구나.`,JPN:`黒東の警備をくぐり抜けて倉庫まで入るとは。なかなかであるな。`,ENG:`I'm impressed you made it past Black East's guards and into our storage, child.`,TWN:`竟然可以突破黑東的戒備闖到倉庫裡，小丫頭蠻厲害的嘛。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_CHILD`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`제자여, 이 도둑을 어쩌면 좋겠느냐?`,JPN:`弟子よ、この泥棒をどうすべきか？`,ENG:`Flora, what should I do with this thief?`,TWN:`徒弟，你說該拿這小偷怎麼辦才好？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`KAUMA_CLAN_NULL_NULL`,text:{KOREA:`화천의 규율대로라면 보물을 훔치려 한 죄인은 두 팔을 자르고 추방하는 것이 옳습니다.`,JPN:`華天の規律どおりだと、宝物を盗もうとした罪人は両腕を切り、追放すべきです。`,ENG:`According to the laws of Huatian, all thieves are to have their arms cut off and exiled.`,TWN:`按照華天的規矩，盜取寶物的犯人必須砍斷雙臂後逐出華天。`},stage:{bg:`CLAN`,slots:{L:null,C:{char_id:`KAUMA_CLAN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`흐음- 그렇지.`,JPN:`ふむ、そうだろうな。`,ENG:`Hmm... That is true.`,TWN:`嗯嗯，沒錯。`},stage:{bg:`CLAN`,slots:{L:null,C:{char_id:`KAUMA_CLAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`아가. 네가 가져가려던 것은 우리 문파의 보물이다.`,JPN:`幼子。お前が持ち出そうとしたものは、我々門派の宝物だ。`,ENG:`Child. What you were trying to steal was our sect's treasure.`,TWN:`小丫頭，你偷的東西是我們門派的寶物。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`서민에겐 아무 의미도 없는 물건일 텐데, 왜 가지려 했지?`,JPN:`庶民には何の意味もないものであるはずだが、どうして持って行こうとした？`,ENG:`To you, it has no meaning. So what were your intentions?`,TWN:`對市井小民來說應該沒什麼意義，你為何要偷呢？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_CHILD`,text:{KOREA:`무기… 몰래 가져오면… 먹으꺼… 준댔어.`,JPN:`武器……こっそり持ってくると……食べ物……くれるって。`,ENG:`If I... take the weapon... they said... they'd feed me.`,TWN:`他說…只要把武器偷給他…就給我…吃的。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`허허, 먹을 것이라.`,JPN:`ほほう、食べ物か。`,ENG:`Ha ha... Was it for food?`,TWN:`呵呵，原來是要吃的。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KAUMA_CLAN_NULL_NULL`,text:{KOREA:`누군가의 사주를 받았군요. 심문해서 알아보겠습니다.`,JPN:`誰かにそそのかされましたね。尋問して調べてみます。`,ENG:`Someone ordered her to steal it. I shall question her further.`,TWN:`看來她是受人指使，讓我來拷問她。`},stage:{bg:`CLAN`,slots:{L:null,C:{char_id:`KAUMA_CLAN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_CHILD`,text:{KOREA:`크르르……!`,JPN:`ガルル……！`,ENG:`Grr...!`,TWN:`呸……！`},stage:{bg:`CLAN`,slots:{L:null,C:{char_id:`KAUMA_CLAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`MEMBER_CLAN_NULL_NULL`,text:{KOREA:`이 녀석! 감히 누구에게 이빨을 들이미느냐!`,JPN:`この野郎！　誰に歯向かっているのか！`,ENG:`Filthy girl! How dare you snarl at our master?!`,TWN:`臭丫頭！好大膽子！竟敢對掌門人不敬！`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`됐다. 어디 그럴 만한 자들이 한 둘이더냐?`,JPN:`止せ。そのような者はどこにでもいる。`,ENG:`Enough. She is one of many who would.`,TWN:`好了，她也不是唯一一個對我不敬的人。`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`그건 그렇고, 아가.`,JPN:`それはさておき、幼子よ。`,ENG:`Nevertheless, child.`,TWN:`丫頭，我問你，`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`FATHER_CLAN_BLACK_NULL`,text:{KOREA:`우리 문파에 문하생으로 들어오지 않겠니?`,JPN:`我々の門派に門下生として入らぬか？`,ENG:`Would you like to join our sect as a disciple?`,TWN:`你要入我們門派成為門生嗎？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_CHILD`,text:{KOREA:`무나생…?`,JPN:`もんかせー……？`,ENG:`"deesaipal...?"`,TWN:`門生…？`},stage:{bg:`CLAN`,slots:{L:null,C:null,R:null}}}];export{e as default};